const text = $node["Telegram Trigger"].json.message.text;
const prompt = text.replace('/create', '').trim();
if (!prompt) {
  throw new Error('Por favor, describe el workflow que quieres crear. Ej: /create Flujo que envie un email diario');
}
return [{ json: { prompt: prompt } }];

try {
  let raw = $node["Cerebro Factory (Groq)"].json.text;
  // Strip markdown if LLM disobeys
  if (raw.startsWith('```json')) raw = raw.substring(7, raw.length - 3);
  else if (raw.startsWith('```')) raw = raw.substring(3, raw.length - 3);
  // Strip /think blocks if model outputs them
  raw = raw.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

  const workflowData = JSON.parse(raw.trim());

  // Validate required structure
  if (!workflowData.name || !workflowData.nodes || !workflowData.connections) {
    throw new Error('JSON incompleto: falta name, nodes o connections');
  }

  // Safety: check for dangerous node types
  const dangerousTypes = ['n8n-nodes-base.ssh', 'n8n-nodes-base.executeCommand'];
  const hasDangerous = workflowData.nodes.some(n => dangerousTypes.includes(n.type));

  return [{ json: { ...workflowData, hasDangerousNodes: hasDangerous } }];
} catch (e) {
  throw new Error('La IA no devolvio un JSON valido: ' + e.message);
}

